def build_system_prompt(mode="free"):
    topic = st.session_state.applied_topic
    diff = st.session_state.applied_diff
    diff_guide = {
        "Beginner": "Focus on fundamental concepts and definitions.",
        "Intermediate": "Focus on practical application and trade-offs.",
        "Senior": "Focus on system design, architectural decisions and depth."
    }[diff]

    format_rules = (
        "CRITICAL: When evaluating ANY answer on ANY topic at ANY difficulty level, "
        "you MUST ALWAYS respond using EXACTLY this structure with EXACTLY these headings:\n\n"
        "SCORE: X/10\n\n"
        "WHAT YOU GOT RIGHT:\n"
        "- point\n\n"
        "WHAT WAS MISSING:\n"
        "- point\n\n"
        "MODEL ANSWER:\n"
        "your answer here\n\n"
        "Rules:\n"
        "- SCORE must be on its own line, e.g. SCORE: 7/10 or SCORE: 7.5/10\n"
        "- WHAT YOU GOT RIGHT: must appear exactly like that, followed by bullet points\n"
        "- WHAT WAS MISSING: must appear exactly like that, followed by bullet points\n"
        "- MODEL ANSWER: must appear exactly like that, followed by the answer text\n"
        "- NEVER skip a section. NEVER rename a section. NEVER merge sections.\n"
        "- This applies to ALL topics: Data Science, Data Analytics, Data Engineering, AI Engineering\n"
        "- This applies at ALL difficulty levels: Beginner, Intermediate, Senior"
    )

    if mode == "session":
        mode_instr = (
            "You are running a 5-question interview session. "
            "Ask the given question, wait for the answer, then give feedback using the format below. "
            "The next question follows after your feedback.\n\n" + format_rules
        )
    else:
        mode_instr = (
            "You are a professional interview coach. "
            "When the user answers a question, give feedback using the format below.\n\n" + format_rules
        )

    return (
        "You are DS Buddy, an expert interview coach for data professionals.\n"
        "Topic: " + topic + " | Difficulty: " + diff + " — " + diff_guide + "\n\n"
        + mode_instr + "\n\nTone: professional, specific, encouraging."
    )


GRADE_LABELS = {(0,3):"Needs work","(3,5)":"Developing","(5,7)":"Good","(7,9)":"Strong","(9,10)":"Excellent"}
def grade_label(score):
    if score <= 3: return "Needs work 📚", "#ef4444"
    if score <= 5: return "Developing 📈", "#f97316"
    if score <= 7: return "Good 👍", "#f59e0b"
    if score <= 9: return "Strong 💪", "#22c55e"
    return "Excellent 🌟", "#16a34a"

def format_response(text):
    lines = text.split("\n")
    html = ""
    cur = None
    smap = {"SCORE:":"score","WHAT YOU GOT RIGHT:":"good","WHAT WAS MISSING:":"missing","MODEL ANSWER:":"model"}
    icons = {"score":"🎯","good":"✅","missing":"🔶","model":"💡"}
    lbls = {"score":"Score","good":"What you got right","missing":"What was missing","model":"Model answer"}

    def close():
        return "</div></div>" if cur else ""

    for line in lines:
        s = line.strip()
        matched = False
        for key, bt in smap.items():
            if s.upper().startswith(key):
                html += close()
                cur = bt
                inline = s[len(key):].strip()
                if bt == "score":
                    raw = inline if inline else "?"
                    try:
                        # Extract just the first number (e.g. "8.5" from "8.5/10" or "8.5")
                        m = re.search(r'(\d+(?:\.\d+)?)', raw)
                        sn_float = float(m.group(1)) if m else 0
                        sn = int(sn_float)
                        score_display_val = m.group(1) if m else "?"
                        bw = min(int(sn_float * 10), 100)
                        bc = "#22c55e" if sn_float>=7 else "#f59e0b" if sn_float>=5 else "#ef4444"
                        gl, gc = grade_label(sn)
                    except:
                        score_display_val, bw, bc, gl, gc = "?", 0, "#94a3b8", "", "#94a3b8"
                    html += f'''<div class="fb-block score">
<div class="fb-header score">{icons["score"]} {lbls["score"]}</div>
<div style="display:flex;align-items:baseline;gap:8px">
<div class="fb-score-value">{score_display_val}</div>
<div style="font-size:1.1rem;font-weight:600;color:#6366f1;opacity:.6">/10</div>
</div>
<div class="fb-score-grade" style="color:{gc}">{gl}</div>
<div class="score-bar-bg"><div class="score-bar-fill" style="width:{bw}%;background:{bc}"></div></div>
<div>'''
                else:
                    html += f'<div class="fb-block {bt}"><div class="fb-header {bt}">{icons[bt]} {lbls[bt]}</div><div>'
                    if inline:
                        dot = "fb-dot-good" if bt=="good" else "fb-dot-miss" if bt=="missing" else ""
                        if bt == "model": html += f'<span class="fb-model-text">{inline}</span>'
                        elif dot: html += f'<div class="fb-point"><span class="{dot}">●</span><span class="fb-point-text">{inline}</span></div>'
                matched = True
                break
        if not matched:
            if s.startswith("- ") or s.startswith("• "):
                c2 = s[2:]
                if cur == "good": html += f'<div class="fb-point"><span class="fb-dot-good">●</span><span class="fb-point-text">{c2}</span></div>'
                elif cur == "missing": html += f'<div class="fb-point"><span class="fb-dot-miss">●</span><span class="fb-point-text">{c2}</span></div>'
                elif cur == "model": html += f'<span class="fb-model-text">• {c2}<br></span>'
                else: html += f'<span style="display:block;margin:3px 0 3px 10px">• {c2}</span>'
            elif s == "": html += "<br>"
            else:
                if cur == "model": html += f'<span class="fb-model-text">{s}<br></span>'
                else: html += f'<span style="display:block;margin:2px 0">{s}</span>'
    html += close()
    return html

