def is_answer_submission(text):
    """Detect if user is submitting an answer vs asking meta questions"""
    lower = text.lower().strip()
    meta_patterns = ["explain simpler","give me a hint","hint","next question","ask me","start session","skip","move on","what is q","what is question"]
    return not any(p in lower for p in meta_patterns) and len(text.strip()) > 10

def send_message(text, mode="free"):
    if not text.strip(): return
    st.session_state.messages.append({"role":"user","content":text})
    with st.spinner("DS Buddy is thinking..."):
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1500,
            system=build_system_prompt(mode),
            messages=st.session_state.messages
        )
        reply = response.content[0].text
    st.session_state.messages.append({"role":"assistant","content":reply})
    st.session_state.total_interactions += 1
    st.session_state.input_key += 1

    # Detect score — support integers and decimals e.g. "8/10" or "8.5/10"
    score_matches = re.findall(r'SCORE:\s*(\d+(?:\.\d+)?)\s*/\s*10', reply, re.IGNORECASE)
    if score_matches:
        try:
            score_f = float(score_matches[0])
            score = int(round(score_f))
            if 0 <= score_f <= 10:
                st.session_state.score_sum += score_f
                st.session_state.score_count += 1
                st.session_state.session_results.append(score_f)
                diff = st.session_state.applied_diff
                st.session_state.diff_counts[diff] += 1
                if st.session_state.session_active:
                    done = st.session_state.session_qs_done + 1
                    st.session_state.session_qs_done = done
                    # Auto-send next question if session not complete
                    if done < 5:
                        qs = st.session_state.get("session_questions", [])
                        if done < len(qs):
                            next_q = qs[done]
                            next_num = done + 1
                            st.session_state.messages.append({
                                "role": "user",
                                "content": f"[SYSTEM: Question {next_num} of 5: \"{next_q}\"]"
                            })
                            with st.spinner("Getting next question..."):
                                r2 = client.messages.create(
                                    model="claude-haiku-4-5-20251001",
                                    max_tokens=400,
                                    system=build_system_prompt("session"),
                                    messages=st.session_state.messages
                                )
                                next_reply = r2.content[0].text
                            st.session_state.messages.append({"role":"assistant","content":next_reply})
        except:
            pass
    st.rerun()

def pick_question():
    pool = QUESTION_BANK[st.session_state.applied_topic][st.session_state.applied_diff]
    used = st.session_state.used_questions
    available = [q for q in pool if q not in used]
    if not available:
        st.session_state.used_questions = []
        available = pool
    q = random.choice(available)
    st.session_state.used_questions.append(q)
    return q

